questionvariables.text:
/* ===== Parameter set selection ===== */
set: rand(3)+1;

/* ===== Given values ===== */
Rs: if set=1 then 50  else if set=2 then 48  else 100;
RL: if set=1 then 8   else if set=2 then 3   else 4;
Vs: if set=1 then 10  else if set=2 then 15  else 20;

/* ===== Derived values ===== */
ratio_sq: float(Rs/RL);
ratio: float(sqrt(ratio_sq));
Zin_matched: float(ratio_sq * RL);
Pmax: float(Vs^2/(4*Rs));

/* Common error: inverted ratio */
ratio_inv: float(1/ratio);
/* Common error: V^2/R instead of V^2/(4R) */
Pmax_wrong: float(Vs^2/Rs);

/* ===== Teacher answers ===== */
ta1: float(ratio);
ta2: float(Zin_matched);
ta3: float(Pmax);

/* Part (d) MCQ: System efficiency at max power transfer */
ta4: [[1, false, "25% — most power is lost in the transformer"],
      [2, true, "50% — half the source power is dissipated in Rs, half goes to the load"],
      [3, false, "100% — the ideal transformer is perfectly efficient"],
      [4, false, "It depends on the turns ratio"]];
ta4_correct: 2;

/* Part (e) MCQ: Why impedance matching is useful */
ta5: [[1, false, "It increases the source voltage to drive larger loads"],
      [2, true, "It maximizes power delivered to the load when source and load impedances differ"],
      [3, false, "It eliminates all power loss in the circuit"],
      [4, false, "It converts AC to DC for the load"]];
ta5_correct: 2;

feedbackvariables.text:
sa1_float: float(ans1);
ref1_float: float(ta1);
prt1_oom_ok: if (abs(ref1_float) > 1.0e-30 and abs(sa1_float) > 1.0e-30 and (abs(sa1_float/ref1_float - 10) < 1.5 or abs(sa1_float/ref1_float - 0.1) < 0.015)) then true else false;
prt1_inverted: if (abs(ratio_inv) > 1.0e-30 and abs(sa1_float) > 1.0e-30 and abs(sa1_float/ratio_inv - 1) < 0.05) then true else false;

sa2_float: float(ans2);
ref2_float: float(ta2);
prt2_oom_ok: if (abs(ref2_float) > 1.0e-30 and abs(sa2_float) > 1.0e-30 and (abs(sa2_float/ref2_float - 10) < 1.5 or abs(sa2_float/ref2_float - 0.1) < 0.015)) then true else false;

sa3_float: float(ans3);
ref3_float: float(ta3);
prt3_oom_ok: if (abs(ref3_float) > 1.0e-30 and abs(sa3_float) > 1.0e-30 and (abs(sa3_float/ref3_float - 10) < 1.5 or abs(sa3_float/ref3_float - 0.1) < 0.015)) then true else false;
prt3_forgot_4: if (abs(Pmax_wrong) > 1.0e-30 and abs(sa3_float) > 1.0e-30 and abs(sa3_float/Pmax_wrong - 1) < 0.05) then true else false;
